   110→/** The non-empty PureList<T> class */
   111→class Cons<ElemType> extends PureListClass<ElemType> {
   112→  ElemType first;
   113→  PureList<ElemType> rest;
   114→  Cons(ElemType f, PureList<ElemType> r) { first = f; rest = r; }
   115→  
   116→  public <ResType> ResType accept(PureListVisitor<ElemType,ResType> v) { return v.forCons(this); }
   117→  public PureList<ElemType> append(PureList<ElemType> addedElts) { 
   118→    return new Cons<ElemType>(first, rest.append(addedElts)); 
   119→  }
   120→  
   121→  public ElemType first() { return first; }
   122→  public PureList<ElemType> rest() { return rest; }
   123→  public boolean contains(ElemType e) {
   124→    if (first.equals(e)) return true;
   125→    else return rest().contains(e);
   126→  }
   127→  
   128→  /** Overrides inherited equals to perform structural equality testing. */
   129→  public boolean equals(Object other) { 
   130→    if (other == null || ! (other instanceof Cons)) return false;
   131→    if (other == this) return true;
   132→    Cons otherCons = (Cons) other;
   133→    return first().equals(otherCons.first()) && rest().equals(otherCons.rest());
   134→  }
   135→  /** Overrides hash code in accord with equals. */
   136→  public int hashCode() { return first().hashCode() + rest().hashCode(); }
   137→  
   138→  public String toString() { return "(" + first + rest.toStringHelp() + ")"; }
   139→  public String toStringHelp() { return " " + first + rest.toStringHelp(); }
   140→}
