/** A class representing a Jam reference cell (mutable box). When printed, displays as (ref <value>).
  * Equality is reference-based (Java default). */
class JamRef implements JamVal {
  /** The mutable value stored in this reference cell. */
  private JamVal value;

  JamRef(JamVal v) { value = v; }

  /** Returns the current value stored in this reference cell. */
  public JamVal value() { return value; }

  /** Stores a new value in this reference cell. */
  public void setValue(JamVal v) { value = v; }

  public <ResType> ResType accept(JamValVisitor<ResType> jvv) { return jvv.forJamRef(this); }

  /** Does NOT override equals so that reference equality (==) is used. */
  public String toString() { return "(ref " + value + ")"; }
}

/** Singleton class representing the Jam unit value, returned by the assignment operator <-. */
