/** Visitor that checks only for duplicate variable names in let/map bindings.
  * Unlike CheckVisitor, it does NOT check for free variables — those are caught
  * at runtime as EvalExceptions. Throws SyntaxException on duplicate binding names. */
class DupCheckVisitor implements ASTVisitor<Void> {
  public static final DupCheckVisitor ONLY = new DupCheckVisitor();
  private DupCheckVisitor() {}

  /** Converts an array to a PureList (same utility as CheckVisitor.arrayToList). */
  static <T> PureList<T> arrayToList(T[] array) {
    int n = array.length;
    PureList<T> list = new Empty<T>();
    for (int i = n - 1; i >= 0; i--) list = list.cons(array[i]);
    return list;
  }

  public Void forIntConstant(IntConstant i) { return null; }
  public Void forBoolConstant(BoolConstant b) { return null; }
  public Void forEmptyConstant(EmptyConstant n) { return null; }
  /** Free variables are not checked here; they cause EvalException at runtime. */
  public Void forVariable(Variable v) { return null; }
  public Void forPrimFun(PrimFun f) { return null; }

  public Void forUnOpApp(UnOpApp u) { u.arg().accept(this); return null; }

  public Void forBinOpApp(BinOpApp b) {
    b.arg1().accept(this); b.arg2().accept(this); return null;
  }

  public Void forApp(App a) {
    a.rator().accept(this);
    for (AST arg : a.args()) arg.accept(this);
    return null;
  }

  public Void forMap(Map m) {
    arrayToList(m.vars()).accept(AnyDuplicatesVisitor.ONLY);
    m.body().accept(this);
    return null;
  }

  public Void forIf(If i) {
    i.test().accept(this); i.conseq().accept(this); i.alt().accept(this); return null;
  }

  public Void forLet(Let l) {
    arrayToList(l.vars()).accept(AnyDuplicatesVisitor.ONLY);
    for (AST exp : l.exps()) exp.accept(this);
    l.body().accept(this);
    return null;
  }
}

